import"./main-vbYdzhsV.js";const o=document.getElementById("nav");window.addEventListener("scroll",()=>{o==null||o.classList.toggle("scrolled",window.scrollY>40)},{passive:!0});const s=document.getElementById("hamburger"),n=document.getElementById("hamburgerClose"),l=document.getElementById("mobileMenu");s==null||s.addEventListener("click",()=>{l.classList.add("open"),document.body.style.overflow="hidden"});n==null||n.addEventListener("click",()=>{l.classList.remove("open"),document.body.style.overflow=""});const d=new IntersectionObserver(e=>e.forEach(t=>{t.isIntersecting&&(t.target.classList.add("visible"),d.unobserve(t.target))}),{threshold:.1});document.querySelectorAll(".reveal").forEach(e=>d.observe(e));
